steps.script:
var acts = PhaseManager.get_current_phase_instance().get_available_actions()
var found = false
for a in acts:
	if a.get("type", "") == "BATTLE_SHOCK_TEST" and a.get("unit_id", "") == "U_KOMMANDOS_H":
		found = true
return found

var cc = tree.current_scene.get_node_or_null("CommandController")
if cc == null:
	return "NO_CONTROLLER"
cc._refresh_ui()
return true

var panel = SceneRefs.main_path("HUD_Right/VBoxContainer/CommandScrollContainer/CommandPanel")
if panel == null:
	return "NO_PANEL"
var sec = panel.get_node_or_null("BattleShockSection")
return sec != null and sec.is_visible_in_tree()

var panel = SceneRefs.main_path("HUD_Right/VBoxContainer/CommandScrollContainer/CommandPanel")
var sec = panel.get_node_or_null("BattleShockSection") if panel else null
if sec == null:
	return "NO_SECTION"
var btns = sec.find_children("*", "Button", true, false)
var found = false
for b in btns:
	if String(b.text).contains("Battle-shock"):
		found = true
return found
